// Generate realistic mock data for our HVAC parameters
const temperature = parseFloat((22 + Math.random() * 4).toFixed(1)); // 22°C to 26°C
const humidity = parseFloat((45 + Math.random() * 15).toFixed(1));    // 45% to 60%
const voltage = parseFloat((225 + Math.random() * 10).toFixed(1));   // 225V to 235V
const current = parseFloat((3.5 + Math.random() * 2.0).toFixed(1));  // 3.5A to 5.5A

// Simple calculation for Energy (Power = V * A, simplified representation)
const energy = parseFloat(((voltage * current) / 1000).toFixed(2)); 

// Simulate 0 to 12 people in the zone
const occupancy = Math.floor(Math.random() * 13); 

// Bundle it into a single professional JSON telemetry packet
msg.payload = {
    temperature: temperature,
    humidity: humidity,
    voltage: voltage,
    current: current,
    energy: energy,
    occupancy: occupancy
};

return msg;

// 1. Capture the incoming telemetry object
const rawData = msg.payload;

// 2. Add ISO 8601 Standard Timestamp
const timestamp = new Date().toISOString();

// 3. Quality Check / Validation Rules
// If any reading falls outside physical reality, clamp it or flag it
let validTemperature = rawData.temperature;
if (validTemperature < -10 || validTemperature > 60) validTemperature = 25.0; // Fail-safe default

let validHumidity = rawData.humidity;
if (validHumidity < 0 || validHumidity > 100) validHumidity = 50.0; // Clamp to human comfort norms

let validOccupancy = rawData.occupancy;
if (validOccupancy < 0) validOccupancy = 0; // Prevent impossible negative headcounts

// 4. Construct the Standardized Message Contract
msg.payload = {
    timestamp: timestamp,
    temperature: parseFloat(validTemperature.toFixed(1)),
    humidity: parseFloat(validHumidity.toFixed(1)),
    voltage: parseFloat(rawData.voltage.toFixed(1)),
    current: parseFloat(rawData.current.toFixed(1)),
    energy: parseFloat(rawData.energy.toFixed(2)),
    occupancy: parseInt(validOccupancy)
};

return msg;
